import folium
def task_func(dic):
    if not dic:
        raise ValueError("Input dictionary is empty.")
    locations = [(k, v['Lat'], v['Lon']) for k, v in dic.items()]
    distances = {}

    folium_map = folium.Map(location=[locations[0][1], locations[0][2]], zoom_start=4)

