        raise ValueError("Input dictionary cannot be empty.")

    m = folium.Map(location=list(dic.values())[0], zoom_start=5)
    distances = {}
    locations = list(dic.items())

    for i in range(len(locations)):
        name1, coord1 = locations[i]
        folium.Marker(location=coord1, popup=name1).add_to(m)
        for j in range(i + 1, len(locations)):
            name2, coord2 = locations[j]
