import numpy as np
from scipy import stats
import pandas as pd
FEATURES = ['feature1', 'feature2', 'feature3', 'feature4', 'feature5']
def task_func(df, dct):
    if not isinstance(df, pd.DataFrame) or not isinstance(dct, dict):
        return "Invalid input"

    for feature in FEATURES:
        if feature not in df.columns:
            return "Invalid input"

    try:
        df_copy = df.copy()
        for col in df_copy.columns:
            if col in FEATURES:
                df_copy[col] = df_copy[col].replace(dct)

        results = {}
        for feature in FEATURES:
            feature_values = df_copy[feature].dropna()
            if feature_values.empty:
                results[feature] = {
                    "mean": np.nan,
                    "median": np.nan,
                    "mode": np.nan,
                    "variance": np.nan
                }
                continue

            mean_val = np.mean(feature_values)
            median_val = np.median(feature_values)
            mode_val = stats.mode(feature_values, keepdims=True)[0]
            variance_val = np.var(feature_values)

            results[feature] = {
                "mean": mean_val,
                "median": median_val,
                "mode": mode_val.tolist(),
                "variance": variance_val
            }
        return results
    except Exception:
        return "Invalid input"

