import base64
from cryptography.fernet import Fernet
def task_func(message, encryption_key):
    if not isinstance(encryption_key, bytes):
        raise ValueError("Encryption key must be a bytes object.")

    try:
        fernet = Fernet(encryption_key)
    except Exception as e:
        raise ValueError("Invalid encryption key provided.") from e

    if not isinstance(message, str):
        raise ValueError("Message must be a string.")

    encrypted_message = fernet.encrypt(message.encode())

    base64_encoded_message = base64.b64encode(encrypted_message)

    return base64_encoded_message.decode()

import re
import pandas as pd
STOPWORDS = ["Those", "are", "the", "words", "to", "ignore"]
def task_func(text):
    sentences = re.split(r'(?<!\w\.\w.)(?<![A-Z][a-z]\.)(?<=\.|\?)\s', text)
    sentence_word_counts = {}
    sentence_index = 1

    for sentence in sentences:
        if sentence.strip():                        
            words = sentence.split()
            word_count = 0
            for word in words:
                if word not in STOPWORDS:
                    word_count += 1
            sentence_word_counts[f"Sentence {sentence_index}"] = word_count
            sentence_index += 1

    return pd.Series(sentence_word_counts)

